const active = roster.filter(r => r.active !== false);


const now = new Date();
const yyyy = now.getFullYear();
const mm   = String(now.getMonth() + 1).padStart(2, '0');
const campaignId = `${yyyy}-${mm}`;              
const runId = `${campaignId}-${Date.now()}`;      


function makeSeed(r, idx) {
  return `${r.userId || r.email}-${campaignId}-${idx}`;
}

function jitterISO(idx, baseMin = 0, spreadMin = 45) {
  const t = new Date(now.getTime() + (baseMin + (idx % spreadMin)) * 60 * 1000);
  return t.toISOString();
}


return active.map((r, idx) => ({
  json: {
    ...r,
    campaignId,                
    runId,                      
    variantSeed: makeSeed(r, idx), 
    companyName: $vars.companyName || '本公司',
    locale: 'zh-TW',

    sendAt: jitterISO(idx)      
  }
}));

