    '出勤紀錄異常補登','工時加班申請審核結果'
  ]}
];

const tones  = ['neutral','formal','urgent_mild','friendly'];
const styles = ['concise','bullet','step_by_step','paragraph'];

const base = 'https://www.google.com';

const weighted = [];
for (const s of scenarios) for (let i=0;i<s.weight;i++) weighted.push(s);

function hash(str){ let h=0; for(let i=0;i<str.length;i++) h=(h*31 + str.charCodeAt(i))>>>0; return h; }


const now  = new Date();
const yyyy = now.getFullYear();
const mm0  = now.getMonth();   
const dd   = now.getDate();
const weekIndex = Math.floor((dd-1)/7); 

const campaignId = `${yyyy}-${String(mm0+1).padStart(2,'0')}`;
const execSalt   = ($vars.campaignSalt || '') + '|' + (items[0]?.json?.runId || '');

return items.map((it, idx) => {
  const uid  = it.json.userId || it.json.email || `U${idx}`;

  const baseIndex = hash(uid) % weighted.length;
  const rotIndex  = (baseIndex
                   + (yyyy*12 + mm0)           
                   + weekIndex                
                   + dd                        
                   + (hash(execSalt) % 5)      
                   ) % weighted.length;
  const sc = weighted[rotIndex];

  const subIdx = (hash(uid + '|' + campaignId + '|' + weekIndex + '|' + dd + '|' + execSalt) % sc.subs.length);
  const subScenario = sc.subs[subIdx];
  const tone  = tones[(hash(uid + '|tone|'  + campaignId + '|' + execSalt) % tones.length)];
  const style = styles[(hash(uid + '|style|' + campaignId + '|' + execSalt) % styles.length)];

  const uidForLink = it.json.userId || it.json.email || uid;
  const link = `${base}?uid=${encodeURIComponent(uidForLink)}&sid=${sc.id}`;

  return {
    json: {
      ...it.json,
      campaignId,
      scenario: sc.label,
      scenarioId: sc.id,
      subScenario,
      tone, style,
      variantSeed: uid + '|' + campaignId + '|' + execSalt,
      trainingLink: link,
      chatInput: `recipientName: ${it.json.name} department: ${it.json.department} scenario: ${sc.label} subScenario: ${subScenario} trainingLink: ${link}`
    }
  };
});

messageValues.message:
=請依下列參數產生一封演練郵件（輸出為單一 JSON）
recipientName: {{$json.name}}
department: {{$json.department}}
scenarioId: {{$json.scenarioId}}
scenarioLabel: {{$json.scenario}}
subScenario: {{$json.subScenario || ({"card_update":"卡片資料需更新","pwd_reset":"密碼即將到期提醒","acct_notice":"帳務異動待釐清","it_renewal":"角色/權限即將到期","travel_update":"行程異動/申請補件"}[$json.scenarioId] || "一般提醒")}}
trainingLink: {{$json.trainingLink}}
companyName: {{$json.companyName || $vars.companyName || "本公司"}}
locale: zh-TW
tone: {{$json.tone || "neutral"}}
style: {{$json.style || "concise"}}
variantSeed: {{$json.variantSeed || ($json.userId || $json.email || "seed")}}

生成要求：
1) 以 scenarioId + subScenario 作為情境核心；不同收件人/不同月份需呈現顯著差異，避免模板化與重複句式，可依 tone/style 做不同寫法。
2) 僅可使用 trainingLink；嚴禁新增其他 URL/縮網址/電話/Email。
3) 合規：不得要求或引導收件者提供密碼、OTP、信用卡/支付資料、身分證/護照、銀行帳號、地址或電話等個資；不得要求登入；不得冒用外部品牌。
4) 80–200 字，語氣自然、專業，不恐嚇。可使用條列或步驟（依 style 決定）。
5) 結尾務必加：「此為公司資安演練郵件，點擊後將前往訓練頁面」。

多樣性規則：
- 依 style 決定結構：concise=單段落；bullet=條列3~5點；step_by_step=步驟2~4步；paragraph=兩段式。
- 依 tone 調整語氣：neutral 平實、formal 正式、urgent_mild 溫和提醒、friendly 親和。
- variantSeed 若為不同值，請在主旨與第一句用不同說法（避免重複模板與開頭）。

請以單一 JSON 輸出：
{ "subject": "...", "bodyText": "...", "bodyHtml": "..." }

