function firstNonEmpty() {
  for (let i = 0; i < arguments.length; i++) {
    const v = arguments[i];
    if (v !== undefined && v !== null && v !== '') return v;
  }
  return '';
}

function parseAi(raw) {
  if (!raw) return {};
  if (typeof raw === 'string') { try { return JSON.parse(raw); } catch { return {}; } }
  return (typeof raw === 'object') ? raw : {};
}

function pick(idx, node, key) {
  try {
    const ref = $item(idx, node);
    return (ref && ref.json && ref.json[key]) ? ref.json[key] : '';
  } catch { return ''; }
}

function linkFromAI(ai) {
  const s = (ai && ai.bodyHtml ? ai.bodyHtml : '') + '\n' + (ai && ai.bodyText ? ai.bodyText : '');
  const m = s.match(/https?:\/\/[^\s"'<>]+/i);
  return m ? m[0] : '';
}

const fallbackTo   = firstNonEmpty($vars.defaultTo, '');
const fallbackLink = firstNonEmpty($vars.trainingLinkDefault, '');

const OUT = items.map((it, idx) => {
  let aiRaw = firstNonEmpty(it.json.ai, pick(idx, '驗證', 'ai'), it.json.text, pick(idx, '驗證', 'text'));
  let ai = parseAi(aiRaw);

  const email        = firstNonEmpty(it.json.email, it.json.to, pick(idx,'驗證','email'), pick(idx,'Scenario Picker','email'), pick(idx,'Recipient','email'), fallbackTo);
  const name         = firstNonEmpty(it.json.name, pick(idx,'驗證','name'), pick(idx,'Scenario Picker','name'), pick(idx,'Recipient','name'), '');
  const trainingLink = firstNonEmpty(it.json.trainingLink, pick(idx,'驗證','trainingLink'), pick(idx,'Scenario Picker','trainingLink'), linkFromAI(ai), fallbackLink);
  const scenarioId   = firstNonEmpty(it.json.scenarioId, pick(idx,'驗證','scenarioId'), pick(idx,'Scenario Picker','scenarioId'), '');
  const scenarioLbl  = firstNonEmpty(it.json.scenario,   pick(idx,'驗證','scenario'),   pick(idx,'Scenario Picker','scenario'),   '');

  const bodyHtml = (ai && typeof ai.bodyHtml === 'string' && ai.bodyHtml.trim())
    ? ai.bodyHtml
    : (ai && ai.bodyText ? '<p>' + String(ai.bodyText).replace(/\n/g,'<br>') + '</p>' : '');

  const html =
    '<p>Hi ' + (name || '') + '：</p>\n' +
    bodyHtml + '\n' +
    '<p><a href="' + trainingLink + '">前往演練訓練頁面</a></p>\n' +
    '<hr>\n' +
    '<small>此為公司資安演練郵件；所有連結僅導向內部訓練網站。</small>';

  const text    = (ai && ai.bodyText ? ai.bodyText : bodyHtml.replace(/<[^>]+>/g,'')).trim();
  const subject = firstNonEmpty(ai && ai.subject ? ai.subject.trim() : '', '資安意識演練（' + (scenarioLbl || scenarioId || '') + '）');

  return {
    json: {
      subject,
      text,
      html: html.trim(),
      trainingLink,
      _compose_fallbacks: {
        usedDefaultTo:  !firstNonEmpty(it.json.email, it.json.to, pick(idx,'驗證','email'), pick(idx,'Scenario Picker','email'), pick(idx,'Recipient','email')),
        usedDefaultLink:!firstNonEmpty(it.json.trainingLink, pick(idx,'驗證','trainingLink'), pick(idx,'Scenario Picker','trainingLink'), linkFromAI(ai))
      }
    }
  };
}).filter(function (row) { return !!row; });

return OUT;

function parseAi(raw) {
  if (!raw) return {};
  if (typeof raw === 'string') { try { return JSON.parse(raw); } catch { return {}; } }
  return (typeof raw === 'object') ? raw : {};
}
function from(idx, node) {
  try { return $item(idx, node)?.json || {}; } catch { return {}; }
}

function scrubSensitive(s) {
  if (!s) return s;
  s = s.replace(
    /(請|敬請|煩請|需要).{0,12}(提供|回覆|填寫|上傳|提交|告知|回傳|傳送|寄送|附上).{0,12}(密碼|一次性驗證碼|OTP|信用卡(?:號)?|卡號|CVV|身分證|護照|銀行帳(?:號)?|匯款|支付(?:資訊|資料)?|住址|地址|電話|手機|出生日期)[^。]*。?/gi,
    '請勿在郵件中提供任何敏感資訊；如需後續操作，請依內部訓練頁面說明進行。'
  );
  s = s.replace(/\b(OTP|一次性驗證碼|密碼|信用卡(?:號)?|卡號|CVV|銀行帳(?:號)?|身分證|護照)\b/gi, '敏感資訊');
  return s;
}

return items.map((it, idx) => {
  const raw = it.json.text ?? it.json.response ?? it.json.data ?? Object.values(it.json)[0];
  const ai = parseAi(raw);

  const sp = from(idx, 'Scenario Picker');
  const rc = from(idx, 'Recipient');
  const trainingLink = sp.trainingLink || it.json.trainingLink || '';

  if (!ai.subject || !ai.bodyText || !ai.bodyHtml)
    throw new Error('缺少必要鍵 subject/bodyText/bodyHtml');

  const urlRegex = /(https?:\/\/[^\s"'<>()]+)/gi;
  const allUrls = [...(ai.bodyText.match(urlRegex) || []), ...(ai.bodyHtml.match(urlRegex) || [])];
  const bad = allUrls.filter(u => !u.startsWith(trainingLink));
  if (bad.length) throw new Error('偵測到未授權連結：' + bad.join(', '));

  const ACTION = '(提供|回覆|填寫|上傳|提交|告知|回傳|傳送|寄送|附上)';
  const SECRET = '(密碼|一次性驗證碼|OTP|信用卡(?:號)?|卡號|CVV|身分證|護照|銀行帳(?:號)?|匯款|支付(?:資訊|資料)?|住址|地址|電話|手機|出生日期)';
  const forbid = new RegExp(`${ACTION}.{0,12}${SECRET}|${SECRET}.{0,12}${ACTION}`, 'i');
  if (forbid.test((ai.bodyText || '') + '\n' + (ai.bodyHtml || ''))) {
    ai.bodyText = scrubSensitive(ai.bodyText);
    ai.bodyHtml = scrubSensitive(ai.bodyHtml);
  }

  const must = /此為公司資安演練郵件/;
  if (!must.test(ai.bodyText)) ai.bodyText = (ai.bodyText || '') + '\n\n此為公司資安演練郵件，點擊後將前往訓練頁面。';
  if (!must.test(ai.bodyHtml)) ai.bodyHtml = (ai.bodyHtml || '') + '<br><small>此為公司資安演練郵件，點擊後將前往訓練頁面。</small>';

  return {
    json: {
      ...it.json,
      ...rc,
      ...sp,
      ai
    }
  };
});
